insert into public.products (
  slug,
  category_id,
  category_slug,
  name_en,
  name_ar,
  notes_en,
  notes_ar,
  kind,
  status,
  visibility,
  show_on_website,
  featured,
  best_seller,
  pricing_model,
  sale_price_per_kg,
  purchase_cost_per_kg,
  blend,
  image_url,
  gallery
)
select
  sp.slug,
  c.id,
  sp.category_slug_denormalized,
  sp.name_en,
  sp.name_ar,
  sp.notes_en,
  sp.notes_ar,
  sp.kind,
  sp.status,
  sp.visibility,
  sp.show_on_website,
  sp.featured,
  sp.best_seller,
  sp.pricing_model,
  sp.sale_price_per_kg,
  sp.purchase_cost_per_kg,
  sp.blend,
  sp.image_url,
  sp.gallery
from seed_products sp
join public.categories c on c.slug = sp.category_slug
on conflict (slug) do update set
  category_id = excluded.category_id,
  category_slug = excluded.category_slug,
  name_en = excluded.name_en,
  name_ar = excluded.name_ar,
  notes_en = excluded.notes_en,
  notes_ar = excluded.notes_ar,
  kind = excluded.kind,
  status = excluded.status,
  visibility = excluded.visibility,
  show_on_website = excluded.show_on_website,
  featured = excluded.featured,
  best_seller = excluded.best_seller,
  pricing_model = excluded.pricing_model,
  sale_price_per_kg = excluded.sale_price_per_kg,
  purchase_cost_per_kg = excluded.purchase_cost_per_kg,
  blend = excluded.blend,
  image_url = excluded.image_url,
  gallery = excluded.gallery;

-- ---------------------------------------------------------------------------
-- Product variants
-- ---------------------------------------------------------------------------
