insert into public.site_settings (
  key,
  scope,
  is_public,
  updated_by,
  value
)
select
  key,
  scope,
  is_public,
  updated_by,
  value
from seed_site_settings
on conflict (key) do update set
  scope = excluded.scope,
  is_public = excluded.is_public,
  updated_by = excluded.updated_by,
  value = excluded.value;

